import{c as a,Q as i,j as l,m as r}from"./chunks/framework.CdiUUa3G.js";const h=JSON.parse('{"title":"ADR-043 — Serbian Cyrillic font gate for sr-Cyrl","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-043.md","filePath":"adr/ADR-043.md"}'),o={name:"adr/ADR-043.md"};function t(n,e,d,s,c,u){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-043-—-serbian-cyrillic-font-gate-for-sr-cyrl" tabindex="-1">ADR-043 — Serbian Cyrillic font gate for <code>sr-Cyrl</code> <a class="header-anchor" href="#adr-043-—-serbian-cyrillic-font-gate-for-sr-cyrl" aria-label="Permalink to &quot;ADR-043 — Serbian Cyrillic font gate for `sr-Cyrl`&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-06 Supersedes in part · <code>docs/adr/ADR-032.md</code> (Cyrillic deferred note) Scope · <code>sr-Cyrl</code> rollout only</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Issue #36 adds Serbian in both Latin (<code>sr-Latn</code>) and Cyrillic (<code>sr-Cyrl</code>). ADR-032 explicitly deferred Cyrillic decisions to a later gate. Before enabling <code>sr-Cyrl</code>, we need an explicit decision on whether to:</p><ul><li>add a new bundled Cyrillic font, or</li><li>keep the current display stack and rely on browser fallback for missing glyphs.</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>For <code>sr-Cyrl</code> in Wave 1.5, Orrery keeps existing bundled fonts and uses system fallback for Cyrillic glyphs where needed.</p><p>No new font files are added in this rollout.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>Preserves current bundle size and avoids adding a global font payload.</li><li>Keeps implementation aligned with URL-based locale rollout in ADR-031.</li><li>Serbian Cyrillic support is required now, while broader Wave 3 script work (Hindi/Arabic) remains separately scheduled.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li><code>sr-Cyrl</code> can ship immediately with no asset pipeline changes.</li><li>No new font download or preload tuning required.</li></ul><p>Negative:</p><ul><li>Typography may vary slightly by platform because fallback glyphs are rendered by system fonts.</li><li>A future design pass may standardize Cyrillic rendering with a dedicated bundled fallback if visual consistency becomes a product requirement.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Add <code>sr-Cyrl</code> to locale config/runtime lists and picker entries.</li><li>Add <code>messages/sr-Cyrl.json</code> and full overlay tree at <code>static/data/i18n/sr-Cyrl/</code>.</li><li>Validate via i18n compile, tests, data validation, and <code>sr-Cyrl</code> e2e smoke.</li></ul>',17)])])}const y=a(o,[["render",t]]);export{h as __pageData,y as default};
